356→DEFINE FUNCTION fn::entity_search_workspace($q: string, $limit: int, $workspace: record<workspace>) {
357→  LET $query = string::lowercase(string::trim($q));
358→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
359→
360→  LET $task_rows = SELECT
361→    id,
362→    "task" AS kind,
363→    title AS text,
364→    extraction_confidence AS confidence,
365→    source_message AS sourceMessage,
366→    priority,
367→    created_at
368→  FROM task
369→  WHERE workspace = $workspace
370→    AND extraction_confidence != NONE
371→    AND string::contains(string::lowercase(title), $query)
372→  ORDER BY created_at DESC
373→  LIMIT $safe_limit;
374→
375→  LET $decision_rows = SELECT
376→    id,
377→    "decision" AS kind,
378→    summary AS text,
379→    extraction_confidence AS confidence,
380→    source_message AS sourceMessage,
381→    priority,
382→    created_at
383→  FROM decision
384→  WHERE workspace = $workspace
385→    AND extraction_confidence != NONE
386→    AND string::contains(string::lowercase(summary), $query)
387→  ORDER BY created_at DESC
388→  LIMIT $safe_limit;
389→
390→  LET $question_rows = SELECT
391→    id,
392→    "question" AS kind,
393→    text AS text,
394→    extraction_confidence AS confidence,
395→    source_message AS sourceMessage,
396→    priority,
397→    created_at
398→  FROM question
399→  WHERE workspace = $workspace
400→    AND extraction_confidence != NONE
401→    AND string::contains(string::lowercase(text), $query)
402→  ORDER BY created_at DESC
403→  LIMIT $safe_limit;
404→
405→  RETURN array::flatten([$task_rows, $decision_rows, $question_rows]);
406→};
